For compiled languages, multi-stage builds are essential. Let's demonstrate with a Go example. Create main.go: package main import ( "encoding/json" "fmt" "net/http" "os"
) func handler(w http.ResponseWriter, r *http.Request) { hostname, _ := os.Hostname() response := map[string]string{ "message": "Hello from Go container!", "hostname": hostname, "path": r.URL.Path, } w.Header().Set("Content-Type", "application/json") json.NewEncoder(w).Encode(response)
} func main() { http.HandleFunc("/", handler) fmt.Println("Server running on port 8080...") http.ListenAndServe(":8080", nil)
} Create go.mod: module container-tp go 1.22 Now create a multi-stage Dockerfile for Go, Dockerfile.go: # Stage 1: Build
FROM golang:1.22 AS builder WORKDIR /app
COPY go.mod .
COPY main.go . RUN CGO_ENABLED=0 GOOS=linux go build -o server . # Stage 2: Run
FROM scratch COPY --from=builder /app/server /server EXPOSE 8080
CMD ["/server"] docker build -f Dockerfile.go -t my-app:v3-go .
docker images my-app scratch is a completely empty image. The resulting image contains only your binary. Typically under 10 MB.

